var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어휴, 유리 언니. 미용실 좀 자주 가야겠다. 머리 푸석푸석한 것 좀 봐.","JPN":"もう、ユリさんったら。美容室にちょくちょく行った方がいいですよ。髪の毛傷みすぎ。","ENG":"Sheesh, Yuri. You really need to get a haircut. It's all frizzy and unkempt.","TWN":"哎呀，悠麗姊姊，你要常去美容院啦，你看你的頭髮亂七八糟的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그러게 그냥 놔두라고 했잖아. 왜 사서 고생이야?","JPN":"だから放っといてっていってるだろ。なんでわざわざそんな面倒なことしなきゃならないんだ？","ENG":"Just leave it alone. Why do you keep bothering?","TWN":"亂就亂，就說不關你的事，幹嘛一直管我的頭髮？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"또, 또 그런다. 평소에도 좀 꾸미고 다니라니깐.","JPN":"はあ、これだから。普段もうちょっとおしゃれしたらいいのに。","ENG":"Seriously? Again? Why don't you groom yourself a little?","TWN":"你又來，就跟你說平時要多打扮。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니나 대장이나 노숙자 꼴로 돌아다니는데 무서워서 누가 도와 달라고 하겠어요?","JPN":"ユリさんも隊長もホームレスの姿で歩き回ってるし、誰も怖くて助けてくれって言えないと思いますよ。","ENG":"With you and Captain looking like hobos, who's gonna come to us asking for help?","TWN":"你和隊長弄得跟流浪漢一樣，人家看到就怕，誰還敢來跟你們求助啦？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 요란한 꼴로 돌아다니면서 여태 안 잡혔던 네가 이상한 거지.","JPN":"そんな派手な格好で歩き回ってるのにまだ捕まってないそっちの方がおかしい。","ENG":"You're the weird one wearing those flashy clothes and still not getting caught all this time.","TWN":"你打扮得一副花枝招展的樣子在路上亂晃，到現在還沒被抓走我才覺得奇妙呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"잔소리 그만하고 라디오나 틀어.","JPN":"小言はもういいからラジオでも付けて。","ENG":"Stop your nagging and turn on the radio.","TWN":"懶得跟你吵，把收音機打開。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"손님 부탁이라면야. 듣고 싶은 채널 있어요?","JPN":"お客様のお望みとあれば。聞きたいチャンネルはありますか？","ENG":"If that's what the customer's wish. Which channel do you want?","TWN":"是，客人，你想聽哪個頻道？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네 정신 사나운 수다만 아니면 아무거나 상관없어.","JPN":"うるさいおしゃべり以外なら何でもいい。","ENG":"Anything, as long as it drowns out your voice.","TWN":"什麼都好，只要不用再聽你嘮叨。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니 너무 야박하다~","JPN":"ユリさん、冷たい～","ENG":"Oof. That was harsh!","TWN":"姊姊，你很冷漠欸～"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"잠깐만 기다려?","JPN":"ちょっと待ってね。","ENG":"Just give me a sec.","TWN":"稍等一下喔？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"……에 대해, 경찰 관계자 분을 모시고 말씀을 들어 보도록 하겠습니다.","JPN":"……について、警察関係者をお招きしてお話を伺います。","ENG":"...we'll learn more after hearing from a police officer.","TWN":"……部分，我們請到警方相關人士蒞臨現場說明。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 제 4 특별기동수사대의 이유미 경정입니다.","JPN":"初めまして。第4特別機動捜査隊のカスカベ・ユミ警視です。","ENG":"Hello, nice to meet you. I'm Major Lee Yumi of SWAT 4.","TWN":"大家好，我是第四特遣機動隊的李悠美警正。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"아직 어린 나이에도 훌륭하게 직무를 수행하신다던데요, 테라사이드 전역도……?","JPN":"まだお若いのに見事に職務を遂行されているということですが、テラサイドの戦域も……？","ENG":"We hear that you've already proven yourself plenty, despite your young age. Did you also participate in the Terraside battles?","TWN":"聽說你年紀輕輕，卻已經有不少的豐功偉業，像是特拉賽德戰役……？"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저 외에도 많은 분들이 활약한 사건입니다.","JPN":"私以外にも多くの方々が活躍した事件です。","ENG":"It wasn't just me. There were many others on that case as well.","TWN":"那不是我一個人的功勞，是許多人一起的努力。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그리고 오늘 할 이야기는 특수능력이 사용된 강력 범죄에 대해서 아니었나요?","JPN":"ところで、今日の内容は特殊能力が使用された凶悪犯罪についてではなかったのですか？","ENG":"Also, wasn't today's topic about the violent crimes using special abilities?","TWN":"再說，今天的主題不是使用特殊能力的暴力犯罪嗎？"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"하하, 그, 그렇죠. 그러면 이 통계를 먼저…….","JPN":"はは、そ、そうですね。それではまずこの統計を……","ENG":"Ha ha. Y-yes, of course. Then let's take a look at the statistics here─","TWN":"哈哈，說的沒錯…那根據這份統計……"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};